    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    /// <summary>Passes (taskId, direction) where direction is -1 (left) or +1 (right).</summary>
    [Parameter, EditorRequired]
    public EventCallback<(int TaskId, int Direction)> OnMoveTask { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }
}

