@page "/board"
@rendermode InteractiveServer
@using sv_d8472ab0d116410bb60c90224be1e846
@using sv_d8472ab0d116410bb60c90224be1e846.Components.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p class="board-loading">Loading board…</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        @for (var i = 0; i < columns.Length; i++)
        {
            var col = columns[i];
            var idx = i;
            <BoardColumn ColumnName="@col"
                         Tasks="GetFilteredTasks(col)"
                         ShowMoveLeft="idx > 0"
                         ShowMoveRight="idx < columns.Length - 1"
                         OnMoveTask="args => MoveTask(args.TaskId, args.Direction)"
                         OnAddTask="args => AddTask(col, args.Title, args.Assignee, args.Priority, args.DueDate)" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private async Task MoveTask(int taskId, int direction)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            // Update local state
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(string status, string title, string assignee, string priority, DateTime dueDate)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to add task: {ex.Message}";
        }
    }
}

.board-loading,
.board-error {
    text-align: center;
    padding: 2rem;
}

.board-error {
    color: #dc3545;
}

/* Stats bar */
.board-stats {
    display: flex;
    gap: 1.5rem;
