+.board-loading,
+.board-error {
+    text-align: center;
+    padding: 2rem;
+}
+
+.board-error {
+    color: #dc3545;
+}
+
+/* Stats bar */
+.board-stats {
+    display: flex;
+    gap: 1.5rem;
+    padding: 1rem;
+    background: #f8f9fa;
+    border-radius: 8px;
+    margin-bottom: 1rem;
+}
+
+.stat {
+    display: flex;
+    flex-direction: column;
+    align-items: center;
+}
+
+.stat-value {
+    font-size: 1.5rem;
+    font-weight: 700;
+}
+
+.stat-label {
+    font-size: 0.85rem;
+    color: #6c757d;
+}
+
+.stat-overdue .stat-value {
+    color: #dc3545;
+}
+
+/* Search */
+.board-search {
+    margin-bottom: 1rem;
+}
+
+.board-search input {
+    width: 100%;
+    padding: 0.5rem 0.75rem;
+    border: 1px solid #dee2e6;
+    border-radius: 6px;
+    font-size: 1rem;
+}
+
+/* Columns */
+.board-columns {
+    display: flex;
+    gap: 1rem;
+}
+
+.board-column {
+    flex: 1;
+    background: #f1f3f5;
+    border-radius: 8px;
+    padding: 0.75rem;
+    min-height: 300px;
+    display: flex;
+    flex-direction: column;
+}
+
+.column-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    margin-bottom: 0.75rem;
+}
+
+.column-header h3 {
+    margin: 0;
+    font-size: 1rem;
+}
+
+.column-count {
+    background: #dee2e6;
+    border-radius: 999px;
+    padding: 0.15rem 0.55rem;
+    font-size: 0.8rem;
+    font-weight: 600;
+}
+
+.column-body {
+    flex: 1;
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+}
+
+/* Task card */
+.task-card {
+    background: #fff;
+    border: 1px solid #dee2e6;
+    border-radius: 6px;
+    padding: 0.75rem;
+}
+
+.task-card h4 {
+    margin: 0 0 0.35rem;
+    font-size: 0.95rem;
+}
+
+.task-assignee {
+    margin: 0 0 0.35rem;
+    font-size: 0.85rem;
+    color: #6c757d;
+}
+
+.priority-badge {
+    display: inline-block;
+    padding: 0.1rem 0.5rem;
+    border-radius: 4px;
+    font-size: 0.75rem;
+    font-weight: 600;
+    margin-right: 0.5rem;
+}
+
+.priority-high {
+    background: #dc3545;
+    color: #fff;
+}
+
+.priority-medium {
+    background: #ffc107;
+    color: #212529;
+}
+
+.priority-low {
+    background: #28a745;
+    color: #fff;
+}
+
+.task-due {
+    font-size: 0.8rem;
+    color: #6c757d;
+}
+
+.task-actions {
+    margin-top: 0.5rem;
+    display: flex;
+    gap: 0.5rem;
+}
+
+.btn-move {
+    font-size: 0.75rem;
+    padding: 0.2rem 0.5rem;
+    border: 1px solid #adb5bd;
+    background: #fff;
+    border-radius: 4px;
+    cursor: pointer;
+}
+
+.btn-move:hover {
+    background: #e9ecef;
+}
+
+/* Add task */
+.btn-add-task {
+    margin-top: 0.5rem;
+    padding: 0.4rem;
+    width: 100%;
+    border: 2px dashed #adb5bd;
+    background: transparent;
+    border-radius: 6px;
+    cursor: pointer;
+    color: #6c757d;
+    font-size: 0.85rem;
+}
+
+.btn-add-task:hover {
+    border-color: #6c757d;
+    color: #212529;
+}
+
+.add-task-form {
+    margin-top: 0.5rem;
+    display: flex;
+    flex-direction: column;
+    gap: 0.4rem;
+    background: #fff;
+    padding: 0.75rem;
+    border-radius: 6px;
+    border: 1px solid #dee2e6;
+}
+
+.add-task-form input,
+.add-task-form select {
+    padding: 0.35rem 0.5rem;
+    border: 1px solid #dee2e6;
+    border-radius: 4px;
+    font-size: 0.85rem;
+}
+
+.form-actions {
+    display: flex;
+    gap: 0.5rem;
+}
+
+.btn-save {
+    padding: 0.35rem 0.75rem;
+    background: #0d6efd;
+    color: #fff;
+    border: none;
+    border-radius: 4px;
+    cursor: pointer;
+    font-size: 0.85rem;
+}
+
+.btn-save:hover {
+    background: #0b5ed7;
+}
+
+.btn-cancel {
+    padding: 0.35rem 0.75rem;
+    background: #fff;
+    border: 1px solid #adb5bd;
+    border-radius: 4px;
+    cursor: pointer;
+    font-size: 0.85rem;
+}
+
+.btn-cancel:hover {
+    background: #e9ecef;
+}
+

